import take from "../../../../../../../../../../../subject_repositories/pull-stream/throughs/take.js"

describe("take", () => {
  it("should only abort the source once after last item passes through", (done) => {
    const items = [1, 2, 3];
    let readCount = 0;
    let abortCount = 0;

    const source = (end: any, cb: Function) => {
      if (end) {
        abortCount++;
        cb(true);
        return;
      }
      if (readCount >= items.length) { cb(true); return; }
      cb(null, items[readCount++]);
    };

    const through = take(1)(source);

    through(null, (end: any, data: any) => {
      // Got first item (last item that passes through)
      through(null, (end2: any) => {
        // This triggers terminate (abortCount becomes 1)
        through(null, (end3: any) => {
          // Original: last=false after terminate, so no second terminate call
          // Mutated: last=true, so terminate called again (abortCount becomes 2)
          expect(abortCount).toBe(1);
          done();
        });
      });
    });
  });
});
```
